using Store;

namespace ShoppingCart.Tests;

[TestClass]
public class AddItemTests
{
    [TestMethod]
    public void AddItem_SingleItem_IncludedInTotal()
    {
        var cart = new Store.ShoppingCart();
        cart.AddItem("SKU-001", quantity: 1, price: 9.99m);

        Assert.AreEqual(9.99m, cart.CalculateTotal());
    }

    [TestMethod]
    public void AddItem_MultipleDistinctItems_AllIncludedInTotal()
    {
        var cart = new Store.ShoppingCart();
        cart.AddItem("SKU-001", quantity: 1, price: 10.00m);
        cart.AddItem("SKU-002", quantity: 2, price: 5.00m);

        Assert.AreEqual(20.00m, cart.CalculateTotal());
    }

    [TestMethod]
    public void AddItem_SameSkuTwice_QuantitiesAccumulate()
    {
        var cart = new Store.ShoppingCart();
        cart.AddItem("SKU-001", quantity: 1, price: 10.00m);
        cart.AddItem("SKU-001", quantity: 3, price: 10.00m);

        Assert.AreEqual(40.00m, cart.CalculateTotal());
    }

    [TestMethod]
    public void AddItem_ZeroQuantity_ThrowsArgumentException()
    {
        var cart = new Store.ShoppingCart();
        Assert.ThrowsException<ArgumentException>(
            () => cart.AddItem("SKU-001", quantity: 0, price: 10.00m));
    }

    [TestMethod]
    public void AddItem_NegativeQuantity_ThrowsArgumentException()
    {
        var cart = new Store.ShoppingCart();
        Assert.ThrowsException<ArgumentException>(
            () => cart.AddItem("SKU-001", quantity: -1, price: 10.00m));
    }

    [TestMethod]
    public void AddItem_NegativePrice_ThrowsArgumentException()
    {
        var cart = new Store.ShoppingCart();
        Assert.ThrowsException<ArgumentException>(
            () => cart.AddItem("SKU-001", quantity: 1, price: -5.00m));
    }

    [TestMethod]
    public void AddItem_NullSku_ThrowsArgumentException()
    {
        var cart = new Store.ShoppingCart();
        Assert.ThrowsException<ArgumentException>(
            () => cart.AddItem(null!, quantity: 1, price: 10.00m));
    }

    [TestMethod]
    public void AddItem_EmptySku_ThrowsArgumentException()
    {
        var cart = new Store.ShoppingCart();
        Assert.ThrowsException<ArgumentException>(
            () => cart.AddItem("", quantity: 1, price: 10.00m));
    }
}

[TestClass]
public class RemoveItemTests
{
    [TestMethod]
    public void RemoveItem_ExistingItem_NoLongerInTotal()
    {
        var cart = new Store.ShoppingCart();
        cart.AddItem("SKU-001", quantity: 1, price: 10.00m);
        cart.AddItem("SKU-002", quantity: 1, price: 5.00m);

        cart.RemoveItem("SKU-001");

        Assert.AreEqual(5.00m, cart.CalculateTotal());
    }

    [TestMethod]
    public void RemoveItem_OnlyItem_TotalBecomesZero()
    {
        var cart = new Store.ShoppingCart();
        cart.AddItem("SKU-001", quantity: 3, price: 10.00m);

        cart.RemoveItem("SKU-001");

        Assert.AreEqual(0m, cart.CalculateTotal());
    }

    [TestMethod]
    public void RemoveItem_NonExistentSku_ThrowsInvalidOperationException()
    {
        var cart = new Store.ShoppingCart();
        Assert.ThrowsException<InvalidOperationException>(
            () => cart.RemoveItem("NO-SUCH-SKU"));
    }

    [TestMethod]
    public void RemoveItem_NullSku_ThrowsArgumentException()
    {
        var cart = new Store.ShoppingCart();
        Assert.ThrowsException<ArgumentException>(
            () => cart.RemoveItem(null!));
    }

    [TestMethod]
    public void RemoveItem_ThenReaddSameItem_Succeeds()
    {
        var cart = new Store.ShoppingCart();
        cart.AddItem("SKU-001", quantity: 1, price: 10.00m);
        cart.RemoveItem("SKU-001");
        cart.AddItem("SKU-001", quantity: 2, price: 15.00m);

        Assert.AreEqual(30.00m, cart.CalculateTotal());
    }
}

[TestClass]
public class CalculateTotalTests
{
    [TestMethod]
    public void CalculateTotal_EmptyCart_ReturnsZero()
    {
        var cart = new Store.ShoppingCart();
        Assert.AreEqual(0m, cart.CalculateTotal());
    }

    [TestMethod]
    public void CalculateTotal_SingleItemMultipleQuantity_ReturnsCorrectTotal()
    {
        var cart = new Store.ShoppingCart();
        cart.AddItem("SKU-001", quantity: 5, price: 3.50m);

        Assert.AreEqual(17.50m, cart.CalculateTotal());
    }

    [TestMethod]
    public void CalculateTotal_MultipleItems_ReturnsSumOfAll()
    {
        var cart = new Store.ShoppingCart();
        cart.AddItem("SKU-001", quantity: 2, price: 10.00m); // 20
        cart.AddItem("SKU-002", quantity: 1, price: 7.50m);  // 7.50
        cart.AddItem("SKU-003", quantity: 3, price: 4.00m);  // 12

        Assert.AreEqual(39.50m, cart.CalculateTotal());
    }

    [TestMethod]
    public void CalculateTotal_AfterRemovingItem_RecalculatesCorrectly()
    {
        var cart = new Store.ShoppingCart();
        cart.AddItem("SKU-001", quantity: 1, price: 25.00m);
        cart.AddItem("SKU-002", quantity: 1, price: 15.00m);
        cart.RemoveItem("SKU-002");

        Assert.AreEqual(25.00m, cart.CalculateTotal());
    }

    [TestMethod]
    public void CalculateTotal_CalledMultipleTimes_ReturnsSameResult()
    {
        var cart = new Store.ShoppingCart();
        cart.AddItem("SKU-001", quantity: 2, price: 10.00m);

        var first = cart.CalculateTotal();
        var second = cart.CalculateTotal();

        Assert.AreEqual(first, second);
    }
}

[TestClass]
public class ApplyCouponTests
{
    [TestMethod]
    public void ApplyCoupon_ValidCode_ReducesTotal()
    {
        var cart = new Store.ShoppingCart();
        cart.AddItem("SKU-001", quantity: 1, price: 100.00m);

        cart.ApplyCoupon("SAVE10");

        Assert.IsTrue(cart.CalculateTotal() < 100.00m,
            "Total should be reduced after applying a coupon.");
    }

    [TestMethod]
    public void ApplyCoupon_InvalidCode_ThrowsInvalidOperationException()
    {
        var cart = new Store.ShoppingCart();
        cart.AddItem("SKU-001", quantity: 1, price: 50.00m);

        Assert.ThrowsException<InvalidOperationException>(
            () => cart.ApplyCoupon("BOGUS"));
    }

    [TestMethod]
    public void ApplyCoupon_NullCode_ThrowsArgumentException()
    {
        var cart = new Store.ShoppingCart();
        Assert.ThrowsException<ArgumentException>(
            () => cart.ApplyCoupon(null!));
    }

    [TestMethod]
    public void ApplyCoupon_EmptyCode_ThrowsArgumentException()
    {
        var cart = new Store.ShoppingCart();
        Assert.ThrowsException<ArgumentException>(
            () => cart.ApplyCoupon(""));
    }

    [TestMethod]
    public void ApplyCoupon_EmptyCart_ThrowsInvalidOperationException()
    {
        var cart = new Store.ShoppingCart();
        Assert.ThrowsException<InvalidOperationException>(
            () => cart.ApplyCoupon("SAVE10"));
    }

    [TestMethod]
    public void ApplyCoupon_TotalNeverGoesBelowZero()
    {
        var cart = new Store.ShoppingCart();
        cart.AddItem("SKU-001", quantity: 1, price: 1.00m);

        cart.ApplyCoupon("SAVE10");

        Assert.IsTrue(cart.CalculateTotal() >= 0m,
            "Total should never be negative after applying a coupon.");
    }
}

